INSERT INTO ai_knowledge_base (category, question, answer, keywords) VALUES
('rooms', 'What room types are available?', 'Atican Beach Resort offers 8 room types: Standard (N55,000/night), Deluxe (N65,000), Double Bed (N75,000), Family (N95,000), Executive (N120,000), Premium Suite (N180,000), Executive Suite (N250,000), and Presidential Suite (N500,000). All rooms include AC, TV, WiFi. Higher tiers add Mini Bar, Ocean View, Lounge, Jacuzzi, Butler, and Private Pool.', ARRAY['room','types','available','price','cost']),
('rooms', 'What is the check-in and check-out time?', 'Check-in is at 2:00 PM and check-out is at 12:00 PM. Early check-in and late check-out are available upon request, subject to availability.', ARRAY['check-in','check-out','time','late','early']),
('rooms', 'Do you have family rooms?', 'Yes! We have Family Rooms that sleep up to 4 guests with 2 bedrooms. They are extra spacious and come with additional amenities for children.', ARRAY['family','room','children','kids']),
('pricing', 'How much does a room cost?', 'Room rates at Atican Beach Resort: Standard N55,000, Deluxe N65,000, Double Bed N75,000, Family N95,000, Executive N120,000, Premium Suite N180,000, Executive Suite N250,000, Presidential Suite N500,000 per night.', ARRAY['price','cost','rate','night','per night']),
('tents', 'What tents are available for events?', 'We offer 4 tent types: Standard Atican Tent (25 chairs + 3 tables, N50,000), Space Atican Tent (50 chairs + 6 tables, N100,000), VIP Atican Tent (100 chairs + 20 tables, N300,000), and VVIP Atican Tent (wooden chairs + sofas, N300,000).', ARRAY['tent','event','beachfront','capacity','chairs']),
('experiences', 'What experiences do you offer?', 'We offer 4 exciting experiences: Bonfire Night (N30,000 per group), Sack Race (N5,000 per group), Beach Ball (N10,000 per group), and Horse Riding (N3,000 per ride).', ARRAY['experience','activity','bonfire','horse','beach ball','sack race']),
('gate fees', 'What are the gate fees?', 'Gate fees at Atican Beach Resort: Children (1-5 years) are FREE, Children (6-14 years) N1,000, Adults N2,000. This includes access to our private beach and pool.', ARRAY['gate','entry','fee','children','adults']),
('dining', 'Do you have a restaurant?', 'Yes! We have a beautiful ocean-view restaurant serving exquisite local and international cuisine. We also offer 24-hour room service for guests.', ARRAY['restaurant','dining','food','room service']),
('location', 'Where is Atican Beach Resort located?', 'Atican Beach Resort is located on the beautiful coastline in Okun-Ajah, Lagos, Nigeria. We are easily accessible from the city center and offer free parking for all guests.', ARRAY['location','address','where','nearby']),
('policies', 'What is your cancellation policy?', 'Cancellations are allowed up to 48 hours before check-in for a full refund. Cancellations within 48 hours are subject to a one-night charge. No-shows are charged the full booking amount.', ARRAY['cancel','refund','policy']),
('policies', 'Do you allow external food and drinks?', 'External food and drinks are subject to a corkage fee of N50,000. We also have a fully stocked bar and restaurant for your convenience.', ARRAY['corkage','external','food','drinks']),
('amenities', 'Is parking available?', 'Yes! We offer free, secure parking for all guests. Our 24/7 security team monitors the parking area.', ARRAY['parking','car','vehicle','secure']),
('amenities', 'Is there WiFi?', 'Yes! We offer complimentary high-speed WiFi throughout the resort. Stay connected while enjoying the beach view.', ARRAY['wifi','internet','connectivity']),
('amenities', 'Do you have a pool?', 'Yes! We have a stunning infinity pool overlooking the ocean, open from 7 AM to 10 PM daily.', ARRAY['pool','swim','infinity']),
('rooms', 'Do you offer short rest bookings?', 'Yes! We offer short rest bookings at N25,000 per hour for guests who need a quick refresh during the day.', ARRAY['short rest','day use','hourly']),
('beach', 'Is the beach private?', 'Yes! Atican Beach Resort has a private, exclusive beach for our guests only. It is beautifully maintained and perfect for relaxation.', ARRAY['beach','private','sand','ocean']),
('kids', 'Is the resort kid-friendly?', 'Absolutely! We welcome families. We have Family Rooms that sleep up to 4, children under 5 enter FREE, and children 6-14 pay N1,000 gate fee.', ARRAY['kids','children','family','child-friendly']),
('events', 'Can I host an event at the resort?', 'Yes! Atican Beach Resort is the perfect venue for weddings, conferences, birthdays, and corporate events. We have event spaces ranging from small setups to VIP spaces for up to 100 guests.', ARRAY['event','wedding','conference','birthday','party']),
('contact', 'How can I contact the resort?', 'You can reach us via email at info@aticanbeachresort.com or through our contact form. Our front desk is also available 24/7.', ARRAY['contact','email','phone','reach']),
('payment', 'What payment methods do you accept?', 'We accept payments via Paystack (cards, bank transfers). All major Nigerian cards are supported. We also accept cash at the front desk.', ARRAY['payment','pay','card','transfer','cash']),
('policies', 'Do you allow smoking?', 'No smoking inside rooms or indoor areas. Designated outdoor smoking areas are available throughout the resort.', ARRAY['smoking','smoke','cigarette']),
('amenities', 'Do you have a spa?', 'Yes! We offer spa and wellness services. Higher-tier rooms include butler service and lounge access.', ARRAY['spa','wellness','massage','relax']),
('gallery', 'Do you have a photo gallery?', 'Yes! Visit our Gallery page to see photos of our rooms, tents, dining areas, experiences, and the beautiful beach.', ARRAY['gallery','photos','pictures'])
